async function fatalShutdown(reason: string, exitCode: number): Promise<void> {
  if (shuttingDown) return;
  shuttingDown = true;
  console.error(`[context-server] ${reason}`);

  runCleanupStep('sessionManager', () => sessionManager.shutdown());
  runCleanupStep('retryManager', () => retryManager.stopBackgroundJob());
  runCleanupStep('shadowEvaluationRuntime', () => shadowEvaluationRuntime.stopShadowEvaluationScheduler());
  runCleanupStep('scheduledGraphRefresh', () => cancelScheduledRefresh());
  runCleanupStep('accessTracker', () => accessTracker.reset());
  runCleanupStep('toolCache', () => toolCache.shutdown());
  runCleanupStep('launcherIdleMonitor', () => {
    if (launcherIdleMonitor) {
      launcherIdleMonitor.stop();
      launcherIdleMonitor = null;
    }
  });

  let deadlineTimer: NodeJS.Timeout | undefined;
  const cleanup = (async () => {
    // Drain the file watcher FIRST: fileWatcher.close() awaits in-flight reindex/remove tasks,
    // which write through requireDb()/getDb() — and getDb() REOPENS the connection if it was
    // already closed. So closeDb() must run AFTER the drain, otherwise a draining task reopens
    // the DB and writes fresh WAL frames after the TRUNCATE checkpoint, leaving a non-empty WAL
    // at rest and defeating the durability guarantee. closeDb() is
    // synchronous, so it still runs to completion uninterrupted once reached; the SHUTDOWN_DEADLINE
    // race only bounds the awaited drains before it, and 010's autocheckpoint keeps the at-rest WAL
    // small even if a pathologically slow drain starves this step.
    await runAsyncCleanupStep('fileWatcher', async () => {
      if (fileWatcher) {
        await fileWatcher.close();
        fileWatcher = null;
      }
    });
    // Fence the ingest worker before closeDb for the same reason as the file
    // watcher above: the worker writes through the DB and would otherwise reopen
    // a closed connection, re-dirtying the WAL and the unclean-shutdown marker.
    await runAsyncCleanupStep('ingestWorker', async () => {
      await stopIngestWorker();
    });
    runCleanupStep('vectorIndex', () => vectorIndex.closeDb());
    // Close MCP transport on shutdown
    runCleanupStep('transport', () => {
      if (transport) {
        transport.close();
        transport = null;
        transportConnectedAt = null;
      }
    });
    await runAsyncCleanupStep('ipcBridge', async () => {
      if (ipcBridge) {
        await ipcBridge.close();
        ipcBridge = null;
      }
    });
    await runAsyncCleanupStep('shutdownHooks', async () => {
      await runShutdownHooks();
    });
    runCleanupStep('registeredTimers', () => clearAllTimers());
  })();

  const timedOut = await Promise.race([
    cleanup.then(() => false),
    new Promise<boolean>((resolve) => {
      deadlineTimer = registerTimeout(() => resolve(true), SHUTDOWN_DEADLINE_MS, { unref: true });
    }),
  ]);

  if (deadlineTimer) {
    clearRegisteredTimer(deadlineTimer);
  }

  if (timedOut) {
    console.error(`[context-server] Shutdown deadline exceeded after ${SHUTDOWN_DEADLINE_MS}ms`);
  }

  process.exit(exitCode);
}

